import "core-js/modules/es.set.symmetric-difference.v2.js";
import "core-js/modules/es.set.union.v2.js";
import quoteService from '../services/quoteService';
import { supabase } from '../services/supabase';
import Icon from '../components/Icons.vue';
export default {
  name: 'QuotesList',
  components: {
    Icon
  },
  data() {
    return {
      quotes: [],
      selectedFilter: 'all',
      searchEmail: '',
      searchQuoteNumber: '',
      selectedType: 'all',
      currentPage: 1,
      itemsPerPage: 10,
      loading: true,
      error: null,
      filters: [{
        value: 'all',
        label: 'Tous'
      }, {
        value: 'pending',
        label: 'En attente'
      }, {
        value: 'validated',
        label: 'Validés'
      }, {
        value: 'expired',
        label: 'Expirés'
      }, {
        value: 'refused',
        label: 'Refusés'
      }]
    };
  },
  computed: {
    filteredQuotes() {
      let filtered = this.quotes;
      if (this.selectedFilter !== 'all') {
        filtered = filtered.filter(q => q.status === this.selectedFilter);
      }
      if (this.searchEmail.trim()) {
        const search = this.searchEmail.toLowerCase();
        filtered = filtered.filter(q => q.customer_email && q.customer_email.toLowerCase().includes(search));
      }
      if (this.searchQuoteNumber.trim()) {
        const search = this.searchQuoteNumber.toLowerCase();
        filtered = filtered.filter(q => q.quote_number && q.quote_number.toLowerCase().includes(search));
      }
      if (this.selectedType !== 'all') {
        filtered = filtered.filter(q => q.quote_type === this.selectedType);
      }
      return filtered;
    },
    totalPages() {
      return Math.ceil(this.filteredQuotes.length / this.itemsPerPage);
    },
    paginatedQuotes() {
      const start = (this.currentPage - 1) * this.itemsPerPage;
      const end = start + this.itemsPerPage;
      return this.filteredQuotes.slice(start, end);
    }
  },
  watch: {
    filteredQuotes() {
      this.currentPage = 1;
    }
  },
  async mounted() {
    await this.loadQuotes();
  },
  methods: {
    async loadQuotes() {
      try {
        this.loading = true;
        this.error = null;
        const quotes = await quoteService.getAll();
        const {
          data: customers
        } = await supabase.from('customers').select('email');
        const customerEmails = new Set(customers?.map(c => c.email.toLowerCase()) || []);
        const {
          data: quoteItems
        } = await supabase.from('quote_items').select('quote_id, price, duration_months, rate_percentage');
        const quoteAmounts = {};
        const quoteRentalInfo = {};
        if (quoteItems) {
          quoteItems.forEach(item => {
            if (!quoteAmounts[item.quote_id]) {
              quoteAmounts[item.quote_id] = 0;
            }
            quoteAmounts[item.quote_id] += parseFloat(item.price);
            if (item.duration_months && item.rate_percentage) {
              if (!quoteRentalInfo[item.quote_id]) {
                quoteRentalInfo[item.quote_id] = {
                  totalPrice: 0,
                  duration: item.duration_months,
                  rate: item.rate_percentage
                };
              }
              quoteRentalInfo[item.quote_id].totalPrice += parseFloat(item.price);
            }
          });
        }
        this.quotes = quotes.map(quote => {
          const baseQuote = {
            ...quote,
            is_registered: quote.customer_email ? customerEmails.has(quote.customer_email.toLowerCase()) : false,
            total_amount: quoteAmounts[quote.id] || 0
          };
          if (quote.quote_type === 'rental_only' && quoteRentalInfo[quote.id]) {
            const rentalInfo = quoteRentalInfo[quote.id];
            const monthlyPayment = this.calculateMonthlyPayment(rentalInfo.totalPrice, rentalInfo.rate, rentalInfo.duration);
            return {
              ...baseQuote,
              monthly_payment: monthlyPayment,
              duration_months: rentalInfo.duration
            };
          }
          return baseQuote;
        });
      } catch (err) {
        this.error = 'Erreur lors du chargement des devis: ' + err.message;
        console.error(err);
      } finally {
        this.loading = false;
      }
    },
    getCountByStatus(status) {
      if (status === 'all') return this.quotes.length;
      return this.quotes.filter(q => q.status === status).length;
    },
    getStatusLabel(status) {
      const labels = {
        draft: 'Brouillon',
        pending: 'En attente',
        validated: 'Validé',
        expired: 'Expiré',
        refused: 'Refusé'
      };
      return labels[status] || status;
    },
    formatDate(dateString) {
      if (!dateString) return '-';
      const date = new Date(dateString);
      return new Intl.DateTimeFormat('fr-FR', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit'
      }).format(date);
    },
    formatPrice(price) {
      return new Intl.NumberFormat('fr-FR', {
        style: 'currency',
        currency: 'EUR'
      }).format(price);
    },
    calculateMonthlyPayment(totalPrice, ratePercentage, durationMonths) {
      if (!totalPrice || !ratePercentage || !durationMonths) return 0;
      const monthlyRate = ratePercentage / 100 / 12;
      const numberOfPayments = durationMonths;
      if (monthlyRate === 0) {
        return totalPrice / numberOfPayments;
      }
      const monthlyPayment = totalPrice * monthlyRate * Math.pow(1 + monthlyRate, numberOfPayments) / (Math.pow(1 + monthlyRate, numberOfPayments) - 1);
      return monthlyPayment;
    },
    goToCreateQuote() {
      this.$emit('navigate', 'create-quote');
    },
    viewQuote(quoteId) {
      this.$emit('navigate', 'quote-detail', quoteId);
    },
    async updateStatus(quoteId, newStatus) {
      try {
        await quoteService.updateWithEmail(quoteId, {
          status: newStatus
        });
        await this.loadQuotes();
      } catch (err) {
        this.error = 'Erreur lors de la mise à jour: ' + err.message;
        console.error(err);
      }
    },
    async deleteQuote(quoteId) {
      if (!confirm('Êtes-vous sûr de vouloir supprimer ce devis ?')) {
        return;
      }
      try {
        await quoteService.delete(quoteId);
        await this.loadQuotes();
      } catch (err) {
        this.error = 'Erreur lors de la suppression: ' + err.message;
        console.error(err);
      }
    }
  }
};
